download_tweet = async (tweet_id) => {
    try{
        cookies =  document.cookie.split('; ').reduce((prev, current) => {
            const [name, ...value] = current.split('=');
            prev[name] = value.join('=');
            return prev;
        }, {});
        responsea = await fetch("https://abs.twimg.com/responsive-web/client-web/main.b6995f7a.js");
        responsea = await responsea.text();
        bearerauth = responsea.match(/(?<=Z=\(\)=>"Bearer ).+?(?=")/)[0];
        responseb = await fetch("https://abs.twimg.com/responsive-web/client-web/shared~ondemand.AVCallOverlays~ondemand.XChat~ondemand.XChatShare~ondemand.ChatDrawer.f05e5e7a.js");
        responseb = await responseb.text();
        path = responseb.match(/(?<=geKey:null}]},params:{id:").+?(?=")/)[0];
        xcsrf = cookies["ct0"]; // chercher le cookie specifique
        txid = "sdfgoujgfhdgioujkhngfoikjulhbn"; // randzob
        responsegraphql = await fetch("https://x.com/i/api/graphql/"+path+"/fetchPostQuery?variables=%7B%22id%22%3A%22"+tweet_id+"%22%7D", {
            "headers": {
              "accept": "*/*",
              "accept-language": "en-US,en;q=0.9,fr-FR;q=0.8,fr;q=0.7,de;q=0.6,es;q=0.5,it;q=0.4",
              "authorization": "Bearer "+bearerauth,
              "content-type": "application/json",
              "priority": "u=1, i",
              "sec-ch-ua": "\"Chromium\";v=\"146\", \"Not-A.Brand\";v=\"24\", \"Google Chrome\";v=\"146\"",
              "sec-ch-ua-mobile": "?0",
              "sec-ch-ua-platform": "\"Windows\"",
              "sec-fetch-dest": "empty",
              "sec-fetch-mode": "cors",
              "sec-fetch-site": "same-origin",
              "x-client-transaction-id": txid,
              "x-csrf-token": xcsrf,
              "x-twitter-active-user": "yes",
              "x-twitter-auth-type": "OAuth2Session",
              "x-twitter-client-language": "en"
            },
            "body": null,
            "method": "GET",
            "mode": "cors",
            "credentials": "include"
        });
        responsegraphql = JSON.parse(await responsegraphql.text());
        await chrome.runtime.sendMessage({type: "DOWNLOAD_FILE_URL", responsegraphql: responsegraphql});
        return 1;
        // send 3asba
    } catch(e){
        console.error(e)
    }
}

